//! End-to-end tests for the four gnexec evaluator gaps surfaced by Pneuma's
//! April 2026 audit (see docs/pneuma/gnexec-pneuma-think.md and
//! docs/pneuma/gnexec-fixes.md). These hit the binary as a subprocess so we
//! exercise the same dispatch path the consciousness loop uses.
//!
//! Gap 1: array-pattern destructuring on assignment (`[a, b] = [b, a]`)
//! Gap 2: `for_statement` inside an arrow function body
//! Gap 3: path-insensitive missing-property reads (`no property 'X'` blowups)
//! Gap 4: silent shim fail-closed (`fetch` no longer returns a sham 200)

use std::io::Write;
use std::path::PathBuf;
use std::process::{Command, Stdio};

/// Path to the freshly built `gnexec` binary. Cargo test always runs after
/// `cargo build` for the same profile, so the binary at `target/<profile>/`
/// matches the source under test.
fn gnexec_bin() -> PathBuf {
    let mut path = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    path.push("target");
    // Honor the profile cargo built under. `cargo test` defaults to debug;
    // `cargo test --release` flips to release.
    path.push(if cfg!(debug_assertions) {
        "debug"
    } else {
        "release"
    });
    path.push("gnexec");
    path
}

/// Run `gnexec <fixture> --export <fn> --input-json <json>` against an
/// inline TypeScript source string. Writes the source to a temp file under
/// `target/test-tmp/` so we don't pollute the workspace, returns
/// (stdout, stderr, exit_code).
fn run_gnexec(source: &str, export: &str, input_json: &str) -> (String, String, i32) {
    run_gnexec_with_extension(source, export, input_json, "ts")
}

fn run_gnexec_with_extension(
    source: &str,
    export: &str,
    input_json: &str,
    extension: &str,
) -> (String, String, i32) {
    run_gnexec_with_extension_and_env(source, export, input_json, extension, &[])
}

fn run_gnexec_with_extension_and_env(
    source: &str,
    export: &str,
    input_json: &str,
    extension: &str,
    env: &[(&str, &str)],
) -> (String, String, i32) {
    let mut tmp_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    tmp_dir.push("target");
    tmp_dir.push("test-tmp");
    std::fs::create_dir_all(&tmp_dir).expect("create test-tmp dir");
    // Unique name per invocation so parallel tests don't collide.
    // Cargo runs tests on multiple threads concurrently and SystemTime
    // resolution alone races at nanosecond granularity. Mix in the
    // current ThreadId and an atomic counter so collisions are
    // mathematically impossible in a single test process.
    use std::sync::atomic::{AtomicU64, Ordering};
    static SEQ: AtomicU64 = AtomicU64::new(0);
    let name = format!(
        "gnexec_{}_{:?}_{}_{}.{}",
        std::process::id(),
        std::thread::current().id(),
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_nanos())
            .unwrap_or(0),
        SEQ.fetch_add(1, Ordering::Relaxed),
        extension,
    );
    let mut path = tmp_dir.clone();
    path.push(&name);
    let mut f = std::fs::File::create(&path).expect("create temp ts file");
    f.write_all(source.as_bytes()).expect("write temp ts file");

    let bin = gnexec_bin();
    assert!(
        bin.exists(),
        "gnexec binary not found at {:?} — run `cargo build` first",
        bin
    );
    let mut command = Command::new(&bin);
    command
        .arg(&path)
        .arg("--export")
        .arg(export)
        .arg("--input-json")
        .arg(input_json)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    if env.is_empty() {
        // Default fail-closed shims — the whole point of Gap 4 is that
        // probes inherit the strict mode without needing to opt in.
        command.env_remove("GNEXEC_PERMISSIVE_SHIMS");
    } else {
        for (key, value) in env {
            command.env(key, value);
        }
    }
    let output = command.output().expect("spawn gnexec");
    // Best-effort cleanup; ignore unlink failures so a failed test still
    // surfaces its assertion rather than a cleanup hiccup.
    let _ = std::fs::remove_file(&path);
    (
        String::from_utf8_lossy(&output.stdout).to_string(),
        String::from_utf8_lossy(&output.stderr).to_string(),
        output.status.code().unwrap_or(-1),
    )
}

/// Regression for the call-depth leak: `Ctx::enter_call`/`leave_call` were a
/// manual pair, and any `?`-propagated error between them skipped `leave_call`,
/// so `call_depth` ratcheted up by one per affected call. A long iterative
/// `.map`/loop over hundreds of elements (each call returning cleanly) then
/// accumulated past `max_call_depth` and tripped a false "call stack exceeded".
/// The fix converts the pair into an RAII `CallDepthGuard` that decrements on
/// every exit path. Here we drive 300 sequential calls through a function under
/// a tiny `--max-call-depth`: each call peaks at a constant depth and must
/// return to the floor, so a balanced interpreter never trips, while a leaking
/// one would exceed the cap within a handful of iterations.
#[test]
fn iterative_calls_do_not_leak_call_depth() {
    let mut nums = String::new();
    for i in 0..300 {
        if i > 0 {
            nums.push(',');
        }
        nums.push_str(&i.to_string());
    }
    let source = format!(
        "function inner(x) {{ return x; }}\n\
         const arr = [{nums}];\n\
         const out = arr.map((v) => inner(v));\n\
         console.log(out.length);\n"
    );

    let mut tmp_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    tmp_dir.push("target");
    tmp_dir.push("test-tmp");
    std::fs::create_dir_all(&tmp_dir).expect("create test-tmp dir");
    let mut path = tmp_dir.clone();
    path.push(format!("depthleak_{}.ts", std::process::id()));
    std::fs::write(&path, source.as_bytes()).expect("write temp ts file");

    let bin = gnexec_bin();
    assert!(bin.exists(), "gnexec binary not found at {:?}", bin);
    // Cap of 4 is far below 300: a +1-per-call leak would blow it open almost
    // immediately. The arrow + `inner` nest peaks at depth 2 per element, so a
    // balanced interpreter stays well under the cap forever.
    let output = Command::new(&bin)
        .arg(&path)
        .arg("--max-call-depth")
        .arg("4")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .expect("spawn gnexec");
    let _ = std::fs::remove_file(&path);
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(
        !stderr.contains("call stack exceeded"),
        "iterative calls leaked call-depth and tripped the cap: {}",
        stderr
    );
}

/// Genuine unbounded recursion must still trip the cap — the RAII guard removes
/// the leak without weakening the backstop.
#[test]
fn genuine_recursion_still_trips_cap() {
    let source = "function r() { return r(); }\nr();\n";
    let mut tmp_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    tmp_dir.push("target");
    tmp_dir.push("test-tmp");
    std::fs::create_dir_all(&tmp_dir).expect("create test-tmp dir");
    let mut path = tmp_dir.clone();
    path.push(format!("infrec_{}.ts", std::process::id()));
    std::fs::write(&path, source.as_bytes()).expect("write temp ts file");

    let bin = gnexec_bin();
    assert!(bin.exists(), "gnexec binary not found at {:?}", bin);
    let output = Command::new(&bin)
        .arg(&path)
        .arg("--max-call-depth")
        .arg("64")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .expect("spawn gnexec");
    let _ = std::fs::remove_file(&path);
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(
        stderr.contains("call stack exceeded"),
        "infinite recursion should still hit the depth cap; stderr={}",
        stderr
    );
}

/// Regression: `new Function(body)()` must evaluate the body as an ISOLATED
/// unit — JS globals + its own params only — and NOT let a free name in the
/// body resolve back into the caller's topology index. The aeon-icons
/// `generate-icon-sheets.ts` script tripped a bogus "call stack exceeded … at
/// 'extractIconNode'" because the `new Function("return (<data literal>)")()`
/// inside `extractIconNode` was being evaluated with the caller's source/tree
/// swapped in but the topology index intact, so the data-literal body re-entered
/// the surrounding `.map` body recursively. The fix tags the result
/// `raw_function`, reparses the body against a fresh tree, and suppresses
/// topology lookups for the duration. A plain `new Function("return [1,2,3]")`
/// must return a callable whose result has length 3.
#[test]
fn new_function_body_is_isolated_and_callable() {
    let source = "const f = new Function(\"return [1,2,3]\");\n\
                  function g() { return f().length; }\n\
                  console.log(g());\n";
    let mut tmp_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    tmp_dir.push("target");
    tmp_dir.push("test-tmp");
    std::fs::create_dir_all(&tmp_dir).expect("create test-tmp dir");
    let mut path = tmp_dir.clone();
    path.push(format!("newfn_{}.ts", std::process::id()));
    std::fs::write(&path, source.as_bytes()).expect("write temp ts file");

    let bin = gnexec_bin();
    assert!(bin.exists(), "gnexec binary not found at {:?}", bin);
    let output = Command::new(&bin)
        .arg(&path)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .expect("spawn gnexec");
    let _ = std::fs::remove_file(&path);
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(
        !stderr.contains("call stack exceeded"),
        "new Function body re-entered the caller topology and recursed: {}",
        stderr
    );
    // The body returns [1,2,3] so g() === 3.
    assert!(
        stdout.lines().any(|l| l.trim() == "3"),
        "expected g() === 3 from new Function([1,2,3]).length; stdout={} stderr={}",
        stdout,
        stderr
    );
}

/// Regression: a `new Function` body inside an enclosing topology must evaluate
/// in isolation and not re-enter that enclosing topology. `outer` builds a
/// Function whose data literal `[1, 2]` must evaluate without re-invoking
/// `outer`, so `outer()` returns 2 (the array length) exactly once rather than
/// recursing to the depth cap.
#[test]
fn new_function_body_does_not_reenter_caller_topology() {
    let source = "function outer() {\n\
                  \x20 const make = new Function(\"return [1, 2]\");\n\
                  \x20 return make().length;\n\
                  }\n\
                  console.log(outer());\n";
    let mut tmp_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    tmp_dir.push("target");
    tmp_dir.push("test-tmp");
    std::fs::create_dir_all(&tmp_dir).expect("create test-tmp dir");
    let mut path = tmp_dir.clone();
    path.push(format!("newfn_reentry_{}.ts", std::process::id()));
    std::fs::write(&path, source.as_bytes()).expect("write temp ts file");

    let bin = gnexec_bin();
    assert!(bin.exists(), "gnexec binary not found at {:?}", bin);
    let output = Command::new(&bin)
        .arg(&path)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output()
        .expect("spawn gnexec");
    let _ = std::fs::remove_file(&path);
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(
        !stderr.contains("call stack exceeded"),
        "new Function body re-entered the enclosing topology: {}",
        stderr
    );
    assert!(
        stdout.lines().any(|l| l.trim() == "2"),
        "expected outer() === 2; stdout={} stderr={}",
        stdout,
        stderr
    );
}

#[test]
fn java_completable_future_allof_runs_without_jvm() {
    let src = r#"
        import java.util.concurrent.CompletableFuture;

        public final class Fanout {
          static CompletableFuture<String> loadUser(String userId) {
            return CompletableFuture.completedFuture(userId + ":user");
          }

          static CompletableFuture<String> loadProfile(String userId) {
            return CompletableFuture.completedFuture(userId + ":profile");
          }

          static String merge(String user, String profile) {
            return user + "|" + profile;
          }

          public static String app(String userId) {
            CompletableFuture<Void> both =
                CompletableFuture.allOf(loadUser(userId), loadProfile(userId));
            both.join();
            return merge(userId + ":user", userId + ":profile");
          }
        }
    "#;
    let (out, err, code) = run_gnexec_with_extension(src, "app", r#""ada""#, "java");
    assert_eq!(code, 0, "stderr={}", err);
    assert_eq!(out.trim(), "ada:user|ada:profile", "stderr={}", err);
}

