#[test]
fn kotlin_named_constructor_args_return_record() {
    let src = r#"
        data class GnosisResult(
          val exitCode: Int,
          val stdout: String,
          val stderr: String,
        )

        fun make(): GnosisResult {
          return GnosisResult(exitCode = 0, stdout = "ok", stderr = "")
        }
    "#;
    let (out, err, code) = run_gnexec_with_extension(src, "make", "{}", "kt");
    assert_eq!(code, 0, "stderr={}", err);
    let value: serde_json::Value = serde_json::from_str(out.trim()).expect("json output");
    assert_eq!(value["__class__"], "GnosisResult", "stderr={}", err);
    assert_eq!(value["exitCode"], 0, "stderr={}", err);
    assert_eq!(value["stdout"], "ok", "stderr={}", err);
    assert_eq!(value["stderr"], "", "stderr={}", err);
}

#[test]
fn kotlin_processbuilder_permissive_returns_shaped_result() {
    let src = r#"
        data class GnosisResult(
          val exitCode: Int,
          val stdout: String,
          val stderr: String,
        )

        fun run(args: List<String>): GnosisResult {
          val command = mutableListOf("gnosis")
          command.addAll(args)
          val process = ProcessBuilder(command).start()
          val stdout = process.inputStream.bufferedReader().use { it.readText() }
          val stderr = process.errorStream.bufferedReader().use { it.readText() }
          val exitCode = process.waitFor()
          return GnosisResult(exitCode = exitCode, stdout = stdout, stderr = stderr)
        }
    "#;
    let (out, err, code) = run_gnexec_with_extension_and_env(
        src,
        "run",
        r#"["lint","demo.gg"]"#,
        "kt",
        &[("GNEXEC_PERMISSIVE_SHIMS", "1")],
    );
    assert_eq!(code, 0, "stderr={}", err);
    let value: serde_json::Value = serde_json::from_str(out.trim()).expect("json output");
    assert_eq!(value["__class__"], "GnosisResult", "stderr={}", err);
    assert_eq!(value["exitCode"], 0, "stderr={}", err);
    assert_eq!(value["stdout"], "", "stderr={}", err);
    assert_eq!(value["stderr"], "", "stderr={}", err);
}

